package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;
import java.lang.reflect.Constructor;

class CartTest {

  // Minimal LineItem stub class to allow compilation
  static class LineItem {
    private final String name;
    private final int quantity;
    private final double price;

    LineItem(String name, int quantity, double price) {
      this.name = name;
      this.quantity = quantity;
      this.price = price;
    }

    // equals and hashCode to support assertEquals on lists
    @Override
    public boolean equals(Object o) {
      if (this == o) return true;
      if (!(o instanceof LineItem)) return false;
      LineItem that = (LineItem) o;
      return quantity == that.quantity &&
             Double.compare(that.price, price) == 0 &&
             (name == null ? that.name == null : name.equals(that.name));
    }

    @Override
    public int hashCode() {
      int result;
      long temp;
      result = name != null ? name.hashCode() : 0;
      result = 31 * result + quantity;
      temp = Double.doubleToLongBits(price);
      result = 31 * result + (int) (temp ^ (temp >>> 32));
      return result;
    }
  }

  @Test
  void testCartConstructorAndGetters() throws Exception {
    List<LineItem> items = new ArrayList<>();
    LineItem item1 = new LineItem("item1", 2, 10.0);
    LineItem item2 = new LineItem("item2", 1, 20.0);
    items.add(item1);
    items.add(item2);

    String buyer = "John Doe";
    String cc = "1234-5678-9012-3456";

    // Use reflection to get Cart class and constructor
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    Constructor<?> constructor = cartClass.getConstructor(List.class, String.class, String.class);
    Object cart = constructor.newInstance(items, buyer, cc);

    // Invoke getters via reflection
    @SuppressWarnings("unchecked")
    List<?> lineItems = (List<?>) cartClass.getMethod("getLineItems").invoke(cart);
    String buyerName = (String) cartClass.getMethod("getBuyerName").invoke(cart);
    String creditCard = (String) cartClass.getMethod("getCreditCard").invoke(cart);

    assertNotNull(cart);
    assertEquals(items, lineItems);
    assertEquals(buyer, buyerName);
    assertEquals(cc, creditCard);
  }
}
